import{_ as a,H as l,f as t,i as r}from"./chunks/framework.Cvt1eIE0.js";const h=JSON.parse('{"title":"NS_Replay Plugin","description":"","frontmatter":{},"headers":[],"relativePath":"en/plugins/ns-replay.md","filePath":"en/plugins/ns-replay.md"}'),i={name:"en/plugins/ns-replay.md"};function n(o,e,s,p,u,d){return l(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="ns-replay-plugin" tabindex="-1">NS_Replay Plugin <a class="header-anchor" href="#ns-replay-plugin" aria-label="Permalink to &quot;NS_Replay Plugin&quot;">​</a></h1><h2 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h2><p>NS_Replay is a versatile full-featured replay system for Unreal Engine, supporting recording, file management, precise seeking, and state synchronization.</p><p><strong>Key Features:</strong></p><ul><li>Real-time game session recording</li><li>Complete replay list management</li><li>Precise time seeking</li><li>Pause/resume playback support</li><li>Adjustable playback speed</li><li>Replay file deletion support</li></ul><p><strong>Supported Platforms:</strong></p><ul><li>Windows (Win64)</li><li>Mac</li><li>iOS</li><li>Android</li><li>Linux</li></ul><p><strong>Engine Version Requirement:</strong> Unreal Engine 5.0.0+</p><h2 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h2><ol><li>Copy the <code>NS_Replay</code> folder to your project&#39;s <code>Plugins</code> directory</li><li>Restart the Unreal Editor</li><li>Enable the <strong>NS_Replay</strong> plugin in the <strong>Plugins</strong> menu</li><li>Recompile your project</li></ol><h2 id="blueprint-node-reference" tabindex="-1">Blueprint Node Reference <a class="header-anchor" href="#blueprint-node-reference" aria-label="Permalink to &quot;Blueprint Node Reference&quot;">​</a></h2><h3 id="startrecording" tabindex="-1">StartRecording <a class="header-anchor" href="#startrecording" aria-label="Permalink to &quot;StartRecording&quot;">​</a></h3><p>Start recording a new replay.</p><p>Parameters:</p><ul><li>ReplayName (String) - Replay file name, uses default if empty</li></ul><p>Returns:</p><ul><li>ReturnValue (Boolean) - Whether recording started successfully</li></ul><h3 id="stoprecording" tabindex="-1">StopRecording <a class="header-anchor" href="#stoprecording" aria-label="Permalink to &quot;StopRecording&quot;">​</a></h3><p>Stop current recording.</p><p>Parameters: None</p><p>Returns:</p><ul><li>ReturnValue (Boolean) - Whether recording stopped successfully</li></ul><h3 id="getreplaylist" tabindex="-1">GetReplayList <a class="header-anchor" href="#getreplaylist" aria-label="Permalink to &quot;GetReplayList&quot;">​</a></h3><p>Get all recorded replays.</p><p>Parameters:</p><ul><li>OutReplayList (FReplayInfo Array) - Output array of replay information</li></ul><p>Returns:</p><ul><li>ReturnValue (Boolean) - Whether list was retrieved successfully</li></ul><h3 id="playreplay" tabindex="-1">PlayReplay <a class="header-anchor" href="#playreplay" aria-label="Permalink to &quot;PlayReplay&quot;">​</a></h3><p>Play specified replay.</p><p>Parameters:</p><ul><li>ReplayName (String) - Name of replay to play</li></ul><p>Returns:</p><ul><li>ReturnValue (Boolean) - Whether playback started successfully</li></ul><h3 id="getreplaytotalduration" tabindex="-1">GetReplayTotalDuration <a class="header-anchor" href="#getreplaytotalduration" aria-label="Permalink to &quot;GetReplayTotalDuration&quot;">​</a></h3><p>Get total duration of current replay (seconds).</p><p>Parameters: None</p><p>Returns:</p><ul><li>ReturnValue (Float) - Total replay duration, returns 0.0 if no active replay</li></ul><h3 id="seektotime" tabindex="-1">SeekToTime <a class="header-anchor" href="#seektotime" aria-label="Permalink to &quot;SeekToTime&quot;">​</a></h3><p>Jump to specified time in replay.</p><p>Parameters:</p><ul><li>TimeInSeconds (Float) - Target time (seconds)</li></ul><p>Returns:</p><ul><li>ReturnValue (Boolean) - Whether seek was successful</li></ul><h3 id="getcurrentdatetime" tabindex="-1">GetCurrentDateTime <a class="header-anchor" href="#getcurrentdatetime" aria-label="Permalink to &quot;GetCurrentDateTime&quot;">​</a></h3><p>Get current system date time in &quot;YYYY-MM-DD HH-MM&quot; format.</p><p>Parameters: None</p><p>Returns:</p><ul><li>ReturnValue (String) - Formatted date time string</li></ul><h3 id="getcurrentreplaytime" tabindex="-1">GetCurrentReplayTime <a class="header-anchor" href="#getcurrentreplaytime" aria-label="Permalink to &quot;GetCurrentReplayTime&quot;">​</a></h3><p>Get current playback time of replay (seconds).</p><p>Parameters: None</p><p>Returns:</p><ul><li>ReturnValue (Float) - Current playback time, returns 0.0 if no active replay</li></ul><h3 id="pausereplay" tabindex="-1">PauseReplay <a class="header-anchor" href="#pausereplay" aria-label="Permalink to &quot;PauseReplay&quot;">​</a></h3><p>Pause replay playback.</p><p>Parameters: None</p><p>Returns:</p><ul><li>ReturnValue (Boolean) - Whether pause was successful</li></ul><h3 id="resumereplay" tabindex="-1">ResumeReplay <a class="header-anchor" href="#resumereplay" aria-label="Permalink to &quot;ResumeReplay&quot;">​</a></h3><p>Resume replay playback.</p><p>Parameters: None</p><p>Returns:</p><ul><li>ReturnValue (Boolean) - Whether resume was successful</li></ul><h3 id="setreplayplaybackspeed" tabindex="-1">SetReplayPlaybackSpeed <a class="header-anchor" href="#setreplayplaybackspeed" aria-label="Permalink to &quot;SetReplayPlaybackSpeed&quot;">​</a></h3><p>Set replay playback speed.</p><p>Parameters:</p><ul><li>PlaybackSpeed (Float) - Playback speed, range 0.1 - 10.0, 1.0 is normal speed</li></ul><p>Returns:</p><ul><li>ReturnValue (Boolean) - Whether speed was set successfully</li></ul><h3 id="deletereplay" tabindex="-1">DeleteReplay <a class="header-anchor" href="#deletereplay" aria-label="Permalink to &quot;DeleteReplay&quot;">​</a></h3><p>Delete specified replay file.</p><p>Parameters:</p><ul><li>ReplayName (String) - Name of replay to delete</li></ul><p>Returns:</p><ul><li>ReturnValue (Boolean) - Whether deletion was successful</li></ul><h3 id="isworldinreplay" tabindex="-1">IsWorldInReplay <a class="header-anchor" href="#isworldinreplay" aria-label="Permalink to &quot;IsWorldInReplay&quot;">​</a></h3><p>Check if current world is in replay mode.</p><p>Parameters: None</p><p>Returns:</p><ul><li>ReturnValue (Boolean) - Whether in replay mode</li></ul><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><ol><li><strong>File Storage Location</strong> - Replay files are stored in <code>[ProjectDir]/Saved/Demos/</code> folder by default</li><li><strong>Name Generation</strong> - If no replay name is specified, auto-generated format is <code>Replay_YYYYMMDD_HHMMSS</code></li><li><strong>Speed Limits</strong> - Playback speed is limited between 0.1x and 10x</li><li><strong>Actor Replication</strong> - Ensure Actors you want to record have proper replication properties set</li><li><strong>Network Mode</strong> - Replay system works in both standalone and network modes</li></ol><h2 id="technical-support" tabindex="-1">Technical Support <a class="header-anchor" href="#technical-support" aria-label="Permalink to &quot;Technical Support&quot;">​</a></h2><ul><li>Author: NodeSmith</li><li>Official Documentation: <a href="https://dztz.github.io/NS_Document/Replay/indexEn.html" target="_blank" rel="noreferrer">https://dztz.github.io/NS_Document/Replay/indexEn.html</a></li><li>Fab Store: com.epicgames.launcher://ue/Fab/product79aa810c-f7a0-4582-b257-287d7f42aefe</li></ul>',86)])])}const y=a(i,[["render",n]]);export{h as __pageData,y as default};
